function largestPalindrome(n) {
    if (n === 1) return 9; // Handle 1-digit numbers
    let upper_limit = Math.pow(10, n) - 1;
    let lower_limit = Math.floor(upper_limit / 10);
    for (let i = upper_limit; i > lower_limit; i--) {
        let temp = i;
        let reverse = 0;
        while (temp !== 0) {
            reverse = reverse * 10 + temp % 10;
            temp = Math.floor(temp / 10);
        }
        let palindrome = i * Math.pow(10, n) + reverse;
        for (let j = upper_limit; j > lower_limit; j--) {
            let product = Math.floor(palindrome / j);
            if (palindrome % j === 0 && product <= upper_limit) {
                return palindrome % 1337;
            }
        }
    }
    return -1;
}
```


    1. If n is 1, return 9 (the largest palindromic product of two 1-digit numbers is 9).
2. Calculate the upper and lower limits for the n-digit numbers.
3. Loop through the numbers in reverse order, starting from the upper limit down to the lower limit.
4. Within the loop, find the reverse of the current iteration number.
5. Calculate the possible palindrome by concatenating the current number and its reverse.
6. Loop through the numbers again to find the two factors of the palindrome.
7. If a palindrome with valid factors is found, return the palindrome modulo 1337.
8. If no such palindrome is found, return -1.

